sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	/*
		When (after) a Configured Sensor is created, find all Sensor Parameters
		 associated with the selected Sensor, and create records in the
		 "Configured Sensor Parameter" table for each of them.
	*/

	var paramKey, paramDefaultValue, paramLabel;
	//The current "Configured Sensor" record that triggered this BR
	var currentConfiguredSensorID = current.getUniqueValue();
	//Selected sensor ID
	var selectedSensorSysID = current.getValue('sensor');
	var grConfiguredSensorParam = new GlideRecord('x_taniu_tan_core_configured_sensor_parameter');
	var grSensorParam = new GlideRecord('x_taniu_tan_core_sensor_parameter');

	//If a sensor has somehow not been selected (which should be impossible, but you never
	// know), then warn.
	if (!selectedSensorSysID) {
		gs.warn(
			'The Configured  Sensor in table ' + current.getTableName() + ' with ID ' +
			currentConfiguredSensorID + ' has been created or updated without a Tanium ' +
			'Sensor selected. This should not be possible. You may want to investigate.'
		);
		return;
		//We could abort the update here, but since this should be impossible, we don't want to
		// risk breaking something - so just log a warning for whoever investigates this later.
	}

	grSensorParam.addQuery('sensor', selectedSensorSysID);
	//It should not be possible to create parameters without keys, but we're being cautious.
	grSensorParam.addNotNullQuery('key');
	grSensorParam.query();

	while (grSensorParam.next()) {
		paramKey = grSensorParam.getValue('key');
		paramDefaultValue = grSensorParam.getValue('default_value') || '';
		paramLabel = grSensorParam.getValue('label') || '';

		grConfiguredSensorParam.initialize();

		grConfiguredSensorParam.setValue(
			'sensor_parameter',
			grSensorParam.getUniqueValue()
		);
		grConfiguredSensorParam.setValue(
			'configured_sensor',
			currentConfiguredSensorID
		);
		grConfiguredSensorParam.setValue(
			'key',
			paramKey
		);

		if (paramDefaultValue) {
			grConfiguredSensorParam.setValue(
				'value',
				paramDefaultValue
			);
		}
		if (paramLabel) {
			grConfiguredSensorParam.setValue(
				'label',
				paramLabel
			);
		}

		grConfiguredSensorParam.insert();
	}

})(current, previous);
